// Subscription Access Controller

const isLoggedIn     = true;
const plan           = "pro";
const accountActive  = true;
const trialDaysLeft  = 0;

// AND: all three must be true
const hasFullAccess = isLoggedIn && accountActive && plan === "pro";

// OR: either trial or paid plan provides access
const hasAnyAccess  = hasFullAccess || trialDaysLeft > 0;

// NOT: flip a boolean
const isBlocked     = !accountActive;

console.log("Full access :", hasFullAccess);  // true
console.log("Any access  :", hasAnyAccess);   // true
console.log("Blocked     :", isBlocked);      // false

// Short-circuit default value
const displayName = "" || "Guest User"; // empty string is falsy
console.log("Display     :", displayName); // "Guest User"

// Logical operators in if conditions
if (isLoggedIn && plan !== "free") {
    console.log("Premium features unlocked.");
}

if (!isLoggedIn || !accountActive) {
    console.log("Please log in or reactivate your account.");
}

