// Day Type Classifier

const dayNumber = 3;
let dayType;

switch (dayNumber) {
    case 1:
    case 2:
        dayType = "Start of week";
        break;
    case 3:
    case 4:
        dayType = "Mid week";
        break;
    // Add case 5 and default here
}

