exercise.solutionCode:
const dayNumber = 3;
let dayType;

switch (dayNumber) {
    case 1:
    case 2:
        dayType = "Start of week";
        break;
    case 3:
    case 4:
        dayType = "Mid week";
        break;
    case 5:
        dayType = "End of week";
        break;
    default:
        dayType = "Weekend";
}

const isWorkday = dayNumber <= 5 ? true : false;

console.log("Day:",      dayNumber);
console.log("Type:",     dayType);
console.log("Work day:", isWorkday);
